import { Directive, Input } from '@angular/core';
import { Validator, NG_VALIDATORS, AbstractControl, ValidatorFn } from '@angular/forms';

export function coordValidator(nameRe: RegExp): ValidatorFn {
  return (control: AbstractControl): { [key: string]: any } | null => {
    const allowed = nameRe.test(control.value);
    return allowed ? null : { 'wrongCoord': { value: control.value } };
  };
}

@Directive({
  selector: '[coordValidator]',
  providers: [{ provide: NG_VALIDATORS, useExisting: CoordValidatorDirective, multi: true }]
})
export class CoordValidatorDirective implements Validator {

  @Input('coordValidator') coord: string;

  constructor() { }

  validate(control: AbstractControl): { [key: string]: any } | null {
    return this.coord ? coordValidator(new RegExp(this.coord, 'i'))(control) : null;
  }

}
