import { Component, OnInit, ViewChild, Output, EventEmitter, ElementRef } from '@angular/core';
import { NgbModalRef, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { Asset } from '../model/asset';

@Component({
  selector: 'app-asset-delete',
  templateUrl: './asset-delete.component.html',
  styleUrls: ['./asset-delete.component.css']
})
export class AssetDeleteComponent implements OnInit {
  
  @ViewChild('content')
  private content: ElementRef;

  @Output()
  confirmDeleteEmit = new EventEmitter<Asset>();

  private modal: NgbModalRef;

  assetForDelete: Asset;



  constructor(private modalService: NgbModal) { }

  ngOnInit() {
  }

  showModal(asset: Asset) {
    this.assetForDelete = asset;
    this.modal = this.modalService.open(this.content, { centered: true, backdropClass: 'dark-backdrop' });
  }


  confirmDelete() {
    this.confirmDeleteEmit.emit(this.assetForDelete);
    this.modal.close();
  }
  

}
