import { Component, OnInit, Output, EventEmitter } from '@angular/core';
import { Asset } from '../model/asset';
import { DataService } from '../services/data.service';

@Component({
  selector: 'app-assets',
  templateUrl: './assets.component.html',
  styleUrls: ['./assets.component.css']
})
export class AssetsComponent implements OnInit {

  assets: Array<Asset>;
  assetsForShow: Array<Asset>;

  searchLength = 0;

  @Output()
  addAssetEmit = new EventEmitter<any>();

  @Output()
  delAssetEmit = new EventEmitter<Asset>();

  @Output()
  assetClickEmit = new EventEmitter<Asset>();


  constructor(private dataService: DataService) {
    this.dataService.getData().subscribe(a => {
      this.assetsForShow = this.assets = a;
    });
  }

  ngOnInit() {
  }

  deleteAsset(asset: Asset) {
    this.assets.splice(this.assets.indexOf(asset), 1);

    if (this.assetsForShow != this.assets)
      this.assetsForShow.splice(this.assetsForShow.indexOf(asset), 1);
  }

  searchAssets(searchValue: string) {
    if (!searchValue) {
      this.assetsForShow = this.assets;
    } else {
      searchValue = searchValue.toLowerCase();
      if (searchValue.length < this.searchLength) {
        this.setAssetsForShow(this.assets, searchValue);
      } else {
        this.setAssetsForShow(this.assetsForShow, searchValue);
      }
    }
    this.searchLength = searchValue.length;
  }

  private setAssetsForShow(source: Array<Asset>, searchValue: string) {
    this.assetsForShow = source.filter(item =>
      item.name.toLowerCase().includes(searchValue)
    );
  }
}
