import { Component, OnInit, ViewChild, ElementRef, Output, EventEmitter } from '@angular/core';
import { NgbModal, NgbModalRef } from '@ng-bootstrap/ng-bootstrap';
import { Asset } from '../model/asset';

@Component({
  selector: 'app-asset-new',
  templateUrl: './asset-new.component.html',
  styleUrls: ['./asset-new.component.css']

})
export class NewAssetComponent implements OnInit {

  @ViewChild('content')
  private content: ElementRef;

  @Output()
  newAssetEmit = new EventEmitter<any>();

  private modal: NgbModalRef;



  constructor(private modalService: NgbModal) { }

  ngOnInit() {
  }

  showModal() {
    this.modal = this.modalService.open(this.content, { centered: true, backdropClass: 'dark-backdrop' });
  }

  onSubmit(asset: Asset) {
 
    this.newAssetEmit.emit(new Asset(asset.name, +asset.lat, +asset.long));

    this.modal.close();
  }

}
